# Search for telegram bot tokens in all config files
import os
import re

token_pattern = re.compile(r'[0-9]{8,10}:[A-Za-z0-9_\-]{30,}')
found_tokens = []

for root, dirs, files in os.walk('/home/marco/.hermes'):
    dirs[:] = [d for d in dirs if d not in ['.git', 'node_modules', '__pycache__']]
    for fname in files:
        if fname in ['.env', 'auth.json', 'config.yaml'] or fname.endswith(('.json', '.yaml', '.yml')):
            fpath = os.path.join(root, fname)
            try:
                with open(fpath, 'rb') as f:
                    content = f.read()
                text = content.decode('utf-8', errors='replace')
                if 'telegram' in text.lower() and ('token' in text.lower() or 'bot' in text.lower()):
                    matches = token_pattern.findall(text)
                    if matches:
                        for m in matches:
                            found_tokens.append((fpath, m[:20] + '...'))
            except:
                pass

print("Found Telegram-related tokens:")
for path, token in found_tokens:
    print(f"  {path}: {token}")
"}

