import os

# Read the process's environment
try:
    with open('/proc/1503/environ', 'rb') as f:
        env_data = f.read()

    env = {}
    for item in env_data.split(b'\x00'):
        if b'=' in item:
            k, _, v = item.partition(b'=')
            env[k.decode('utf-8', errors='replace')] = v.decode('utf-8', errors='replace')

    # Look for telegram-related env vars
    print("Telegram-related env vars in gateway process:")
    for k, v in sorted(env.items()):
        if 'telegram' in k.lower() or 'bot' in k.lower():
            print(f"  {k}: {v[:50]}...")

    print("\nAll env vars containing 'token':")
    for k, v in sorted(env.items()):
        if 'token' in k.lower():
            print(f"  {k}: {v[:50]}...")
except Exception as e:
    print(f"Error: {e}")
"}

